test_that("read_gcp() works and handles errors", {

  gcp_data <- create_dummy_gcp_data(10)

  # Train the model using the GCPs generated by create_demo_data()
  gcps <- read_gcp(
    source_x = gcp_data$source_x,
    source_y = gcp_data$source_y,
    target_x = gcp_data$source_x + gcp_data$dx,
    target_y = gcp_data$source_y + gcp_data$dy
  )

  expect_s3_class(gcps, "gcp")
  expect_s3_class(gcps, "data.frame")
  expect_named(gcps, c("source_x", "source_y", "target_x", "target_y", "dx", "dy"))

})

test_that("read_gcp() returns errors", {
  gcp_data <- create_dummy_gcp_data(10)

  # Non-numeric input
  expect_error(
    read_gcp(
      source_x = as.character(gcp_data$source_x),
      source_y = gcp_data$source_y,
      target_x = gcp_data$source_x + gcp_data$dx,
      target_y = gcp_data$source_y + gcp_data$dy
    ),
    "All input coordinates must be finite numbers."
  )

  # Mismatched lengths
  expect_error(
    read_gcp(
      source_x = gcp_data$source_x,
      source_y = gcp_data$source_y[-1], # Shorter length
      target_x = gcp_data$source_x + gcp_data$dx,
      target_y = gcp_data$source_y + gcp_data$dy
    ),
    "All input vectors must have the same length."
  )

  # NA values
  gcp_data_with_na <- gcp_data
  gcp_data_with_na$source_x[1] <- NA
  expect_error(
    read_gcp(
      source_x = gcp_data_with_na$source_x,
      source_y = gcp_data_with_na$source_y,
      target_x = gcp_data_with_na$source_x + gcp_data_with_na$dx,
      target_y = gcp_data_with_na$source_y + gcp_data_with_na$dy
    ),
    "All input coordinates must be finite numbers."
  )
})

