test_that("plot.gcp returns a valid ggplot object with correct data", {

  gcp_data <- create_dummy_gcp_data(10)
  gcps <- read_gcp(
    source_x = gcp_data$source_x,
    source_y = gcp_data$source_y,
    target_x = gcp_data$source_x + gcp_data$dx,
    target_y = gcp_data$source_y + gcp_data$dy
  )
  p <- plot(gcps)

  # Test 1: The output must be a ggplot object
  expect_s3_class(p, "ggplot")

  # Test 2: Check if exaggeration factor works
  exaggeration_factor <- 2
  p_exaggerated <- plot(
    gcps,
    exaggeration_factor = exaggeration_factor
  )
  plot_data <- ggplot2::layer_data(p_exaggerated, 1)

  # Calculate expected endpoints
  expected_xend <- gcps$source_x +
    exaggeration_factor * (gcps$target_x - gcps$source_x)
  expected_yend <- gcps$source_y +
    exaggeration_factor * (gcps$target_y - gcps$source_y)

  # Check if the calculated endpoints in the plot match the expected ones
  expect_equal(plot_data$xend, expected_xend)
  expect_equal(plot_data$yend, expected_yend)

})
